window.__QUIZ_DATA__=[{"id":"objective>Further Maths>2015>1","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : SURDS","question":"Simplify:1-2&radic;5&nbsp;2+3&radic;2&nbsp;","images":[],"options":{"A":"14(2&radic;2&nbsp; + 6&radic;5&nbsp; - 4&radic;10&nbsp;)","B":"1/14 (2 - 3&radic;2&nbsp; - 4&radic;5&nbsp; - 6&radic;10&nbsp;)","C":"1/14 (3&radic;2&nbsp; + 4&radic;5&nbsp;  - 6&radic;10 - 2&nbsp;)","D":"14(2 + 3&radic;2&nbsp; - 6&radic;5&nbsp; + 4&radic;10&nbsp;"},"answer":"C","explanation":"1-2\u221a52+3\u221a2=(1-2\u221a5)(2-3\u221a2)(2+3\u221a2)(2-3\u221a2)=2-3\u221a2-4\u221a5+6\u221a1022-(3\u221a2)2    =2-3\u221a2-4\u221a5+6\u221a104-9(2)=2-3\u221a2-4\u221a5+6\u221a-14    -114(-4\u221a5+2-3\u221a+6\u221a10)=114(3\u221a2+4\u221a5-6\u221a10-2)","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>2","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : TRIGONOMETRY","question":"Solve: 2cosx - 1 = 0, for 0 \u2264 x \u2264 2\u03c0","images":[],"options":{"A":"2\u03c03,4\u03c03","B":"\u03c06,5\u03c06","C":"\u03c05,2\u03c05","D":"\u03c03,5\u03c03"},"answer":"D","explanation":"2Cos x - 1 = 0   \u2234 2 cos x = 1   cosx=12    x = cos-1 ( 1/2 )    x = 600 or 3000    where; \u03c0 = 1800    \u2192600=\u03c03    \u21923000=300180\u03c0=106\u03c0=53\u03c0    \u2234x=\u03c03or5\u03c03","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>3","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : INDICES AND LOGARITHMIC FUNCTIONS","question":"Solve 4(2x2) = 82","images":[],"options":{"A":"1 and 2","B":"1 and -2","C":"-1 and 2","D":"-1 and -2"},"answer":"A","explanation":"4(2x2) = 8x    22(2x2) = 23x ; 22+x2 = 23x    2 + x2 = 3x     x2 - 3x + 2 = 0     x2 - 3x + 2 = 0    x2 - 2x - x + 2 = 0 ; x(x - 2) -1(x - 2) = 0     (x - 2)(x - 1) = 0     x - 2 = 0 or x - 1 = 0     x = 2 or 1","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>4","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : INDICES AND LOGARITHMIC FUNCTIONS","question":"If log3x = log93, find the value of x.","images":[],"options":{"A":"32","B":"31/2","C":"31/3","D":"2 1/3"},"answer":"B","explanation":"log3 x = log9 3 , x = ?     log3 x = log3 23 ; log3 x = 1/2 log3 3     log3 x = 1/2 ; x = 31/2","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>5","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : BINOMIAL THEOREM","question":"Findthethirdtermof(x2-1)8indescendingorderofx","images":[],"options":{"A":"x78","B":"7x616","C":"7x54","D":"358x4"},"answer":"B","explanation":"( x/2 - 1)8 - Binomial Expansion     From Pascal's triangle ; 1 8 28 56 70 56 28 81     28(x2)6(-1)2=28\u00d7x664\u00d71=2864x6    =716x6","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>6","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : FUNCTIONS","question":"Given that f:x \u2192 : x2 and g: x \u2192 x + 3 where x \u220a R, find fog(2)","images":[],"options":{"A":"25","B":"9","C":"7","D":"5"},"answer":"A","explanation":"Given; f(x) = x2 , g(x) = x + 3     fog(2) = ? = f(g(2))    g(2) = 2 + 3 = 5     \u2234 f(g(2)) = f(5)    f(s) = 52 = 25","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>7","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : POLYNOMIAL FUNCTIONS","question":"Giventhat2x(x+6)(x+3)=Px+6+Qx+3,findPandQ","images":[],"options":{"A":"P = 4 and Q = 2","B":"P = --2 and Q = 4","C":"P = 4 and Q = -2","D":"P = -2 and Q = 4"},"answer":"C","explanation":"2x(x+6)(x+3)=px+6+Qx+3    2x(x+6)(x+3)=p(x+3)+Q(x+6)(x+6)(x+3)    2x = P(x - 3) + Q(x + 6)     \u2192 x + 3 = 0 , x = -3     2(-3) = p(-3 + 3) + Q(-3 + 6)    -6 = p(0) + Q(3)   ;   -6 = 3Q     Q = 6/3 = -2     \u2192 x + 6 = 0 , x = -6   2(-6) = p(-6 + 3) + Q(-6 + 6)    -12 = -3p + Q(0)  ; -3p = -12     p=-12-3    p = 4     \u2234 p = 4, Q = -2","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>8","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : MATRICES AND DETERMINANTS","question":"GiventhatP=-2134andQ=5-32-1,findPQ-QP","images":[],"options":{"A":"0000","B":"271216-15","C":"-20-612-8","D":"111230-11"},"answer":"D","explanation":"-21345-32-1=Q    PQ - QP = ?     -2134  5-32-1-5-32-1-2134    =-10+26-115-8-9-4--10-95-12-4-32-4=-8523-13-19-7-7-2=111230-11","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>9","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : POLYNOMIAL FUNCTIONS","question":"Which of the following is a factor of the polynomial 6x4 + 2x3 + 15x + 5?","images":[],"options":{"A":"3x + 1","B":"x + 1","C":"2x + 1","D":"x + 2"},"answer":"A","explanation":"'3x + 1' is a factor of 6x4 + 2x3 + 15x + 5    From zeros theorem, 3x + 1 = 0 ; 3x = -1 , x = -1/3     \u22346(181)+2(-127)-153+5=227-227-5+5=0    \u2234 '3x + 1' is a factor","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>10","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : INVERSE OF A 2 X 2 MATRICES","question":"Giventhatf:x\u21922x-12-x,x\u2260-2,findf-1,theinverseoff","images":[],"options":{"A":"f-1:x\u21921+2x2-x,x\u22602","B":"f-1:x\u21921-2xx+2,x\u2260-2","C":"f-1:x\u21921-2xx-2,x\u2260-2","D":"f1:x\u21921+2xx-2,x\u2260-2"},"answer":"A","explanation":"f : x \u2192 2x-1/2x+x    f(x) = 2x-1/2+x ; f-1(x) = ?     Let f(x) be h    h = 2x-1/2+x ; h(2+x) = 2x - 1     2h + hx = 2x - 1 ; 2x - hx = 2h + 1    x(h + 2) = 2h + 1    x=2h+1-h+2  \u2234f-1x=2x+1-x+2=2x+12-x","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>11","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : SEQUENCES AND SERIES","question":"If 36, p, 9/4 and q are consecutive terms of an exponential sequence (G.P), find the sum of p and q.","images":[],"options":{"A":"916","B":"8116","C":"9","D":"9916"},"answer":"D","explanation":"GP : 36, P, q/4, q, ... p + q = ?    Recall,commonratio,r=TnTn-1=T2T1=T3T2=T4T3    \u2234P36=94\u00f7p;p2=94x36;p2=81    p=9\u2234r=T2T1=936=14    Alsor=T4T3=q\u00f794     \u2234 1/4 = q \u00f7 9/4 ; 9/4 = 4q    16q=9,q=916\u2234p+q=9+916=9916","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>12","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : POLYNOMIAL FUNCTIONS","question":"Find the minimum value of y = x2 + 6x - 12","images":[],"options":{"A":"-21","B":"-12","C":"-6","D":"-3"},"answer":"A","explanation":"Minimum value of y = x2 + 6x = 12     y = x2 + 6x - 12     dydx=2x+6    Equate  it to zero, it minimum     2x+6=0;2x=-6;x=-62=-3    \u2234 y = (-3)2 + 6(-3) - 12     y = 9 - 18 - 12     y = -9 - 12     y = -12","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>13","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : CO-ORDINATE GEOMETRY OF STRAIGHT LINES","question":"Alinepassesthroughtheoriginandthepoint(114,212)  Use this information to answer this question    What is the gradient of the line?","images":[],"options":{"A":"1","B":"2","C":"3","D":"4"},"answer":"B","explanation":"(0,0)and(114,212)    Recall,m=y2-y1x2-x1    m=212-0\u00f7114-0    52\u00f754=52x45=42    m = 2","marks":"1","difficulty":"1"},{"id":"objective>Further Maths>2015>14","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : CO-ORDINATE GEOMETRY OF STRAIGHT LINES","question":"Alinepassesthroughtheoriginandthepoint(114,212)  Use this information to answer this question  Find the y coordinate of the line when x = 4","images":[],"options":{"A":"2","B":"4","C":"6","D":"8"},"answer":"D","explanation":"x = 4   y = ?  m = 2   Recall, y = mx + c , c = 0     y = 2(4) + 0 ; y = 8","marks":"1","difficulty":"1"},{"id":"objective>Further Maths>2015>15","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : PERMUTATION AND COMBINATIONS.","question":"In how many ways can a committee of five be selected from eight students if two particular students are to be included?","images":[],"options":{"A":"20","B":"28","C":"54","D":"58"},"answer":"A","explanation":"r = 5 , n = 8     2 must be included     8-2C5-2 = 6C3     Recall,nCr=n!(n-r)!r!    \u22346C3=6!(6-3)!3!=6!3!3!=6x5x4x3!3!x6=20","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>16","subject":"Further Maths","year":"2015","type":"Objective","topic":"VECTORS AND MECHANICS : VECTORS","question":"If x = i - 3j and y = 6i + j, calculate the angle between x and y.","images":[],"options":{"A":"60\u00b0","B":"75\u00b0","C":"81\u00b0","D":"85\u00b0"},"answer":"C","explanation":"x = i - 3j , y = 6i + j , \u03b8 = ?     Recall, Cos \u03b8 = a.b/|a|.|b|     where; |a| = \u221a 12 + (3)2 = \u221a 1+9 = \u221a 10     |b| = \u221a 62+12 = \u221a 36+1 = \u221a 37     Cos\u03b8=6+(-3)\u221a10x\u221a37=3\u221a370    \u03b8=Cos-1(3\u221a370)    \u03b8 = Cos-1 (0.1559)  \u03b8 = 810","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>17","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : DIFFERENTIATION","question":"The gradient of a curve at the point (-2, 0) is 3x2 - 4x. Find the equation of the curve.","images":[],"options":{"A":"y = 6x - 4","B":"y = 6x2 - 4 + 12","C":"y = x3 - 2x2","D":"y = x3 - 2x2 + 16"},"answer":"D","explanation":"Given; Gradient, m = 3x2 - 4x     m=dydx=3x2-4x    dy = (3x2 - 4x)dx ; \u222bdy = \u222b(3x2 - 4x)dx     y = \u222b3x2 dx - 4\u222bx - dx     y = 3x2dx - 4\u222bx - dx    y = 3x3/3 - 4x2/2 + C    y = x3 - 2x2 + k at (x, y) = (-2, 0)    0 = (-2)3 -2(-2)2 + k   0 = -8 -2(4) + k ; -k = -8 - 8     -k = -16 ; k = 16     \u2234  y = x3 - 2x2 + 16","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>18","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : POLYNOMIAL FUNCTIONS","question":"If\u03b1and\u03b2aretherootsofx2+x-2=0,findthevalueof(1\u03b12+1\u03b22)","images":[],"options":{"A":"54","B":"34","C":"14","D":"-34"},"answer":"A","explanation":"Roots = \u221d and \u03b2  x2 + x - 2 = 0 ; a = 1, b = 1, c = -2     Recall,\u221d+\u03b2=-ba=-11=-1    \u221d\u03b2 = c/a = -2/1 = -2     \u22341\u221d2+1\u03b22=\u03b22+\u221d2\u221d2\u03b22=\u221d2+\u03b22(\u221d\u03b2)2    =54","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>19","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : POLYNOMIAL FUNCTIONS","question":"Given that x2 + 4x + k \u2261(x + r)2 + 1, find the values of k and r","images":[],"options":{"A":"k = 5, r = -1","B":"k = 5, r = 2","C":"k = 2, r = 5","D":"k = 1, r = 5"},"answer":"B","explanation":"Given; x2 + 4x + k = (x+r)2 + 1     x2 + 4x + k = (x + r)(x + r) + 1  x2 + 4x + k = x2 + (2xr)+(r2 + 1)    Comparing co-efficients     \u2192 4x = 2xr     4=2r;r=42=2    Also; \u2192 k = r2 + 1    k = (2)2 + 1 = 4 + 1 = 5","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>20","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : LOGICAL REASONING","question":"Given the statements: p : the subject is difficult. q: I will do my best. Which of the following is equivalent to \"Although the subject is difficult, I will do my best\".","images":[],"options":{"A":"p V q","B":"\u223cp V q","C":"p \u223c (\u2227q)","D":"p \u2227q"},"answer":"D","explanation":"'Although the subject is difficult, I will do my best'    p: the subject is difficult     q : I will do my best     \u2234 (p^q) is equivalent to it because the '^' sign stands for 'and'","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>21","subject":"Further Maths","year":"2015","type":"Objective","topic":"VECTORS AND MECHANICS : STATICS","question":"Forces of magnitude 8N and 5N act on a body as shown in the diagram.  Use this information to answer this question      Calculate, correct to 2 decimal places, the resultant force acting at O.","images":["data:image/png;base64,"],"options":{"A":"14.06N","B":"13.00N","C":"9.83N","D":"8.26N"},"answer":"D","explanation":"R = ? (2 d.p)    \u2211fy = 8sin45 + 5sin 300 = 8.156     \u2211fx = 8Cos450 - 5Cos 300 = 1.326     Recall, R = \u221a\u2211fy2+\u2211fx2    R = \u221a(8.656)2 + (1.326)2    R = \u221a 68.277     R = 8.26N","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>22","subject":"Further Maths","year":"2015","type":"Objective","topic":"VECTORS AND MECHANICS : STATICS","question":"Forces of magnitude 8N and 5N act on a body as shown in the diagram.  Use this information to answer this question    Calculate, correct to 2 decimal places, the angle that the resultant makes with the horizontal.","images":["data:image/png;base64,"],"options":{"A":"80.76\u00b0","B":"75.00\u00b0","C":"71.99\u00b0","D":"15.00\u00b0"},"answer":"A","explanation":"\u03b8 = ?     Recall,tan\u03b8=\u2211fy\u2211fx    tan\u03b8=8.6561.326=6.5279    tan\u03b8=6.5279;\u03b8=tan-1(6.5279)    \u03b8 = 80.760","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>23","subject":"Further Maths","year":"2015","type":"Objective","topic":"VECTORS AND MECHANICS : VECTORS","question":"Given that r = 2i - j, s = 3i + 5j amd t = 6i - 2j, find the magnitude of (2r + s - t)","images":[],"options":{"A":"&radic;15&nbsp;","B":"4","C":"&radic;24&nbsp;","D":"&radic;26&nbsp;"},"answer":"D","explanation":"r  = 2i - j ,  s  = 3i + 5j,  t  = 6i - 2j ; |2r + s - t| = ?   ( 2r + s  - t) = 2(2i - j) + (3i + 5j) - (6i - 2)  = 4i - 2j + 3i + 5j - 6i + 2j   = 4i + 3i + 6i - 2j + 5j + 2j   = i + 5j     \u2234 |2r  + s  = \u221a(1)2+(5)2 = \u221a1+25 = \u221a26     (24 - 25) statistics","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>24","subject":"Further Maths","year":"2015","type":"Objective","topic":"STATISTICS AND PROBABILITY : STATISTICS","question":"Marks012345No. of candidates6481093  The table above shows the distribution of marks scored by students in a test  Use the information to answer this question    How many candidates scored above the median mark?","images":[],"options":{"A":"3","B":"12","C":"22","D":"30"},"answer":"B","explanation":"Median position = 40/2 = 20th   Median = 3   N o  of students that scored above median mark = 9 + 3 = 12","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>25","subject":"Further Maths","year":"2015","type":"Objective","topic":"STATISTICS AND PROBABILITY : STATISTICS","question":"Marks012345No. of candidates6481093  The table above shows the distribution of marks scored by students in a test  Use the information to answer this question  Find the inter-quartile range of the distribution.","images":[],"options":{"A":"4","B":"3","C":"2","D":"1"},"answer":"B","explanation":"Inter - quartile Range = ?     Recall, I.Q.R = Q3 - Q1 , N = 40     where ; Q3 = 3/4 N = 3/4 x 40 = 3 x 10 = 30th \u2234 4 month     Q1 = 1/4 N = 1/4 x 40 = 1 x 10 = 10th    \u2234 I.Q.R = 4 - 1 = 3","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>26","subject":"Further Maths","year":"2015","type":"Objective","topic":"VECTORS AND MECHANICS : THE CONCEPTS OF MOTION","question":"A mass of 75kg is placed on a lift. Find the force exerted by the floor of the lift on the mass when the lift is moving up with a constant velocity. [Take g = 9.8ms-2]","images":[],"options":{"A":"750N","B":"745N","C":"735N","D":"98N"},"answer":"C","explanation":"Given; m = 75kg , g = 9.8ms-2 , F = ?     Recall, F = ma     F = 75 x 9.8     F = 735N","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>27","subject":"Further Maths","year":"2015","type":"Objective","topic":"STATISTICS AND PROBABILITY : PROBABILITY","question":"Each of the 90 students in a class speak at least Igbo and Hause. If 56 students speak Igbo and 50 speak Hausa, find the probability that a student selected at random from the class speaks Igbo only.","images":[],"options":{"A":"28/45","B":"4/9","C":"8/45","D":"1/9"},"answer":"B","explanation":"Probability (set theory n(Uy)) = 900 , n(I) = 56 , n(H) = 50 , Pr(Ig only) = ?     Pr (I only) = ?          (56 - x) + x + (50 - x) = 90     56 - x + x + 50 - x = 90     106 - x = 90     x = 106 - 90    x = 16          n(I only) = 40   n(H only) = 34   n(I n H) = 16    \u2234Pr(Ionly)=n(I only)n(U)    =4090=49","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>28","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : FUNCTIONS","question":"If1+2x-163-x=-3,findthevaluesofx.","images":[],"options":{"A":"x = 3, -2","B":"x = 4, -2/3","C":"x = -4, 3/2","D":"x = 4, -3/2"},"answer":"D","explanation":"1+2x-163-x=-3    (1 + 2x)(3 - x) - (-6) = -3     3 -x + 6x - 2x2 + 6 = -3     -2x2 + 5x + 9 + 3 = 0     2x2 - 5x - 12 = 0     2x2 + 3x - 8x - 12 = 0  ; x(2x + 3) -4(2x + 3) = 0     (2x + 3)(x - 4) = 0    2x + 3 = 0 or x - 4 = 0     2x = 3 or x = 4     x=-32or4","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>29","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : INTEGRATION","question":"Find\u222bx3+5x+1x3dx","images":[],"options":{"A":"x2 + 10x + c","B":"x+53x3+x4+c","C":"x - 5x2 - 2x2 + c","D":"x-5x-12x2+c"},"answer":"D","explanation":"\u222bx3+5x+1x3.dx=\u222b(x3x3+5xx3+1x3)dx    \u222b(1+5x2+1x3)dx=\u222b1.dx+\u222b5x2dx+\u222b1x3dx    = 1 \u222bdx + 5 \u222b x-2.dx + fx-3.dx     =x+5x-1-1+x-2-2+C    =x-5x-1-x-22+C    =x-5x-12x2+C","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>30","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : CO-ORDINATE GEOMETRY OF STRAIGHT LINES","question":"Find the coordinates of the point which divides the line joining P(-2, 3) and Q(4, 6) internally in the ratio 2 : 3","images":[],"options":{"A":"(525,25)","B":"(25,525)","C":"(-25,525)","D":"(25,225)"},"answer":"D","explanation":"P (-2, 2) , Q (4, 3) Ratio = 2: 3    Recall,(x,y)=(px2+qx1p+q,py2+qy1p+q)    (x,y)=(2(4)+3(-2)2+3,2(3)+3(2)2+3)=(8-65,6+65)    (x,y)=(25,125)=(25,225)","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>31","subject":"Further Maths","year":"2015","type":"Objective","topic":"VECTORS AND MECHANICS : THE CONCEPTS OF MOTION","question":"A particle starts from rest and moves in a straight line such that its acceleration after t seconds is given by a = (3t - 2) ms-2.  Use this information to answer this question    Find the other time when the velocity would be zero.","images":[],"options":{"A":"1/3 seconds","B":"3/4 seconds","C":"4/3 seconds","D":"2 seconds"},"answer":"C","explanation":"a = (3t - 2) ms-2     when will v = 0ms-1    \u222bdadt=\u222bdv2dt2\u222b(3t-2)dt    v=3t22-2t,whenv=0    3t22-2t=0;3t22-2t=0    t(3t2-2)=0    t=0or3t2-2=0    t=0or3t=4;t=0secor43secs","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>32","subject":"Further Maths","year":"2015","type":"Objective","topic":"VECTORS AND MECHANICS : THE CONCEPTS OF MOTION","question":"A particle starts from rest and moves in a straight line such that its acceleration after t seconds is given by a = (3t - 2) ms-2.  Use this information to answer this question  Find the distance covered after 3 seconds","images":[],"options":{"A":"10m","B":"9m","C":"13/3 m","D":"9/2 m"},"answer":"D","explanation":"S after 3s = ?     v=3t22-2t    S=\u222b(3t22-2t)dt    S=\u222b3t22.dt-\u222b2t.dt    S=32\u222bt2.dt-2\u222bt.dt=32.t33-2t22    S=t32-t2whent=3s    S=332-32=27-92=272-182=92=412m","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>33","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : DIFFERENTIATION","question":"Given that y = 4 - 9x and \u0394x = 0.1, calculate \u0394y","images":[],"options":{"A":"9.0","B":"0.9","C":"-0.3","D":"-0.9"},"answer":"D","explanation":"y = 4 - 9x , \u2206x = 0.1 , \u2206y = ?     y = 4 - 9x     y + \u2206y = 4 - 9(x + \u2206x)    y + \u2206y = 4 - 9x - 9\u2206x     \u2206y = 4 - 9x - 9\u2206x - y     \u2206y = 4 - 9x - 9\u2206x - y     \u2206y = 4 - 9x - 9\u2206x - (4 - 9x) = 4 - 9x - 9\u2206x - 4 + 9x     \u2206y = 9\u2206x     \u2206y = -9\u2206x ; \u2206y = -9(-0.1) = - 0.9","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>34","subject":"Further Maths","year":"2015","type":"Objective","topic":"STATISTICS AND PROBABILITY : PROBABILITY","question":"Four fair coins are tossed once. Calculate the probability of obtaining equal number of heads and tails.","images":[],"options":{"A":"1/4","B":"3/8","C":"1/2","D":"15/16"},"answer":"B","explanation":"Possible outcome for 4 coins tossing = 2 x 2 x 2 x 2 = 16     No( equal H & T) =   (1) HHTT  (2) HTTH   (3) HTHT  (4)  THTH   (5) THHT   (6) TTHH    Pr.(equalH&T)=616=38","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>35","subject":"Further Maths","year":"2015","type":"Objective","topic":"STATISTICS AND PROBABILITY : STATISTICS","question":"In calculating the mean of 8 numbers, a boy mistakenly used 17 instead of 25 as one of the numbers. If he obtained 20 as the mean, find the correct mean.","images":[],"options":{"A":"24","B":"23","C":"21","D":"19"},"answer":"C","explanation":"Mean=\u2211fxN    \u2234x+178=20    x - 17 = 160 ; x = 160 - 17 = 143     x+258=143+258=1688=21","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>36","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : PERMUTATION AND COMBINATIONS.","question":"Simplify: nCr \u00f7 nCr-1","images":[],"options":{"A":"n(n-r)r","B":"nr(n-r)","C":"1r(n-r)","D":"n-r+1)r"},"answer":"C","explanation":"nCr \u00f7 nCr-1    n!(n-r)!r!\u00f7n!(n-r)!(r-1)!=n!(n-r)!r!x(n-r)!(r-1)!n!    =(n-r-1)!(r-1)!(n-r)!(r)!=(n-r-1)!(r-1)!(n-r)(n-r-1)!r(r-1)!    =1r(n-r)!","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>37","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : TRIGONOMETRY","question":"If 2 sin2\u03b8 = 1 + cos \u03b8, 0\u00b0 \u2264 \u03b8 \u2264 90\u00b0, find the value of \u03b8","images":[],"options":{"A":"90\u00b0","B":"60\u00b0","C":"45\u00b0","D":"30\u00b0"},"answer":"B","explanation":"2sin2 \u03b8 = 1 + Cos \u03b8     Recall, Sin2 \u03b8 + Cos2 \u03b8 = 1    Sin2 \u03b8 = 1 - Cos2 \u03b8     2(1 - cos2 \u03b8) = 1 + Cos \u03b8    Let Cos \u03b8 = x     2(1 - x2) = 1 + x     2 - 2x2 = 1 + x     2x2 + x + 1 - 2 = 0     2x2 + x - 1 = 0     2x2 + 2x - 1 = 0     2x(x + 1) -1(x + 1) = 0     (2x - 1) (x + 1) = 0     2x - 1 = 0 or x + 1 = 0     2x = 1 or x = -1     x=12or-1    \u2192 x = 1/2  \u2192  x = -1    Cos \u03b8 = 1/2  Cos \u03b8 = -1   \u03b8 = Cos-1(0.5)    \u03b8 = Cos-1(-1)    \u03b8 = 600","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>38","subject":"Further Maths","year":"2015","type":"Objective","topic":"VECTORS AND MECHANICS : THE CONCEPTS OF MOTION","question":"A 24N force acts on a body such that it changes its velocity from 5m-1 to 9m-1 in 2 seconds. If the body is travelling in a straight line, calculate the distance covered during the period.","images":[],"options":{"A":"22m","B":"18m","C":"14m","D":"10m"},"answer":"C","explanation":"Given; u = 5ms-1 , v = 9ms-1 , t = 2s , S = ?     S=ut+12at2    S=5(2)+12a(2)2;S=10+2a    But;a=v-ut;a=9-52    a-42=2ms2    S = 10 + 2a     S = 10 + 2(2) = 10 + 4    S = 14m","marks":"1","difficulty":"3"},{"id":"objective>Further Maths>2015>39","subject":"Further Maths","year":"2015","type":"Objective","topic":"PURE MATHEMATICS : SEQUENCES AND SERIES","question":"The sum, Sn, of a sequence is given by Sn = 2n2 - 5. Find the 6th term.","images":[],"options":{"A":"112","B":"67","C":"45","D":"22"},"answer":"A","explanation":"Given; Sn = 2n2 - 5     T6 = ?     Recall, Tn = Sn - Sn-1    T6 = S6 - S5     T6 = [2(6)2 - 5] - [2(5)2 - 5]    T6 = [2(36) - 5] - [2(25) - 5]    T6 = [72 - 5][50 - 5] = 67 - 45    T6 = 22","marks":"1","difficulty":"2"},{"id":"objective>Further Maths>2015>40","subject":"Further Maths","year":"2015","type":"Objective","topic":"VECTORS AND MECHANICS : STATICS","question":"Forces F1 (8N, 030\u00b0) and F2 (10N), 150\u00b0) act on a particle. Find the horizontal component of the resultant force.","images":[],"options":{"A":"1.7N","B":"4.5N","C":"9.0N","D":"13.0N"},"answer":"A","explanation":"F1 (8N, 0300) and F2 (10N, 1500)     \u2211fx = ?          F1x = 10Cos 300 = 10 \u221a3/2 = 5\u221a3    F2x = -8Cos 300 = -8 \u221a3/2 = -4\u221a3    for   Fx = 5\u221a3 - 4\u221a3    = \u221a3 = 1.7N","marks":"1","difficulty":"3"}];